{"operationName":"PageLoadAnalyticsData_Init_Pdp","variables":{"isBestbuyMember":true,"skuId":"6674708","input":{"salesChannel":"LargeView"},"isBadgeEnabled":false,"isBadgeV2Enabled":true,"bsinBuyingOptionsInput":{"skuId":"6674708","bsin":"JJGH3KQYP8","salesChannel":"LargeView","postalCode":"","locationId":"1436"}},"extensions":{"clientLibrary":{"name":"@apollo/client","version":"4.1.6"}},"query":"query PageLoadAnalyticsData_Init_Pdp($skuId: String!, $input: ProductItemPriceInput!, $isBestbuyMember: Boolean!, $isBadgeEnabled: Boolean!, $isBadgeV2Enabled: Boolean!, $bsinBuyingOptionsInput: BsinBuyingOptionsInput!) {
  productBySkuId(skuId: $skuId) {
    skuId
    ...AnalyticsFulfillmentOptionsFragment
    buyingOptions {
      skuId
      type
      product {
        ...AnalyticsFulfillmentOptionsFragment
        __typename
        skuId
        openBoxCondition
      }
      __typename
    }
    seller {
      id
      __typename
    }
    whatItIs
    hierarchy {
      bbypres {
        id
        primary
        categoryDetail {
          name
          seoUrl
          broaderTerms {
            primaryLineage {
              id
              name
              seoUrl
              sequence
              __typename
            }
            __typename
          }
          __typename
        }
        __typename
      }
      __typename
    }
    arModels {
      uri
      format
      __typename
    }
    reviewInfo {
      averageRating
      reviewCount
      __typename
    }
    price(input: $input) {
      customerPrice
      currentPrice
      priceEventType
      puckDisplayMessage
      heroRenderPriceOptions
      paymentOptions {
        numberOfInstallments
        installmentAmount
        vendor
        isDisplayable
        type
        __typename
      }
      financeOption {
        monthlyPayment
        offerId
        __typename
      }
      tieredOffersTracking {
        amountConsideredToNextTier
        amountRemainingToNextTier
        nextTierId
        quantityConsideredToNextTier
        quantityRemainingToNextTier
        savings
        savingsType
        tieredOffersGroupName
        trackingBy
        tiers {
          discountValue
          minPurchaseAmount
          minQuantity
          offerId
          qualified
          tierId
          __typename
        }
        __typename
      }
      __typename
    }
    productVariationDetailDisplay {
      type
      title
      variationTypes {
        definition
        displayName
        rawName
        __typename
      }
      productVariations {
        shortName
        color
        colorCategory
        sku
        variations {
          rawName
          value
          __typename
        }
        product {
          name {
            short
            __typename
          }
          seller {
            classification
            id
            __typename
          }
          __typename
          skuId
          openBoxCondition
        }
        __typename
      }
      __typename
    }
    ...AnalyticsBadgesFragment @include(if: $isBadgeEnabled)
    ...AnalyticsBadgesV2Fragment @include(if: $isBadgeV2Enabled)
    operationalAttributes {
      values
      __typename
    }
    ...featuredSkuRankingId
    __typename
    openBoxCondition
  }
  bsinBuyingOptions(input: $bsinBuyingOptionsInput) {
    lowestAvailableBSINPrice
    highestAvailableBSINPrice
    __typename
    bsin
  }
}

fragment AnalyticsFulfillmentOptionsFragment on Product {
  __typename
  skuId
  openBoxCondition
}

fragment featuredSkuRankingId on Product {
  featuredSkuRank(filter: {isBestbuyMember: $isBestbuyMember}) {
    rankingId
    __typename
  }
  __typename
  skuId
  openBoxCondition
}

fragment AnalyticsBadgesFragment on Product {
  badges {
    detailsHref
    displayName
    endDate
    imageHref
    sortOrder
    startDate
    typeCode
    __typename
  }
  __typename
  skuId
  openBoxCondition
}

fragment AnalyticsBadgesV2Fragment on Product {
  badgesV2 {
    badgeId
    label
    __typename
  }
  __typename
  skuId
  openBoxCondition
}"}
